patch:
diff --git a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
index 00efd3c0eb72..aca710933d2a 100644
--- a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
+++ b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
@@ -7159,10 +7159,76 @@ bool SimplifyCFGOpt::simplifySwitch(SwitchInst *SI, IRBuilder<> &Builder) {
   if (Options.ConvertSwitchRangeToICmp && turnSwitchRangeIntoICmp(SI, Builder))
     return requestResimplify();

+  if (auto *Cmp = dyn_cast<CmpIntrinsic>(SI->getCondition())) {
+    bool Signed = Cmp->isSigned();
+    Value *LHS = Cmp->getLHS();
+    Value *RHS = Cmp->getRHS();
+
+    BasicBlock *LTDest = SI->getDefaultDest();
+    BasicBlock *EQDest = SI->getDefaultDest();
+    BasicBlock *GTDest = SI->getDefaultDest();
+
+    for (auto Case : SI->cases()) {
+      int64_t Val = Case.getCaseValue()->getSExtValue();
+      if (Val == -1) LTDest = Case.getCaseSuccessor();
+      else if (Val == 0) EQDest = Case.getCaseSuccessor();
+      else if (Val == 1) GTDest = Case.getCaseSuccessor();
+    }
+
+    BasicBlock *TrueDest = nullptr;
+    BasicBlock *FalseDest = nullptr;
+    ICmpInst::Predicate Pred = ICmpInst::BAD_ICMP_PREDICATE;
+
+    if (LTDest == EQDest && EQDest != GTDest) {
+      Pred = Signed ? ICmpInst::ICMP_SGT : ICmpInst::ICMP_UGT;
+      TrueDest = GTDest;
+      FalseDest = LTDest;
+    } else if (LTDest != EQDest && EQDest == GTDest) {
+      Pred = Signed ? ICmpInst::ICMP_SLT : ICmpInst::ICMP_ULT;
+      TrueDest = LTDest;
+      FalseDest = GTDest;
+    } else if (LTDest == GTDest && LTDest != EQDest) {
+      Pred = ICmpInst::ICMP_EQ;
+      TrueDest = EQDest;
+      FalseDest = LTDest;
+    }
+
+    if (Pred != ICmpInst::BAD_ICMP_PREDICATE) {
+      Value *ICmp = Builder.CreateICmp(Pred, LHS, RHS, "cmp");
+      Builder.CreateCondBr(ICmp, TrueDest, FalseDest);
+      
+      // Get all unique successors
+      SmallPtrSet<BasicBlock*, 4> Successors;
+      for (auto *Succ : successors(BB))
+        Successors.insert(Succ);
+
+      for (auto *Succ : Successors) {
+        // Find how many times we branch to Succ now
+        int ExpectedEdges = (Succ == TrueDest ? 1 : 0) + (Succ == FalseDest ? 1 : 0);
+        if (TrueDest == FalseDest && Succ == TrueDest) ExpectedEdges = 1;
+
+        int CurrentEdges = 0;
+        for (auto *S : successors(BB))
+          if (S == Succ) CurrentEdges++;
+
+        // Remove extra edges in PHIs
+        for (int i = ExpectedEdges; i < CurrentEdges; ++i)
+          Succ->removePredecessor(BB);
+      }
+
+      SI->eraseFromParent();
+      SI->eraseFromParent();
+      if (Cmp->use_empty()) {
+        auto *CmpInst = cast<Instruction>(Cmp);
+        CmpInst->eraseFromParent();
+      }
+      return requestResimplify();
+    }
+  }
+
   // Remove unreachable cases.
   if (eliminateDeadSwitchCases(SI, DTU, Options.AC, DL))
     return requestResimplify();
-
   if (trySwitchToSelect(SI, Builder, DTU, DL, TTI))
     return requestResimplify();

